function magazynDokumentSkanUstawIlosc(documentId,value){
  const session=magazynDokumentSkanSesja(documentId),quantity=Math.max(1,Math.min(10000,Math.trunc(Number(value)||1)));if(session.pending)session.pending.quantity=quantity;magazynDokumentKamera.quantity=quantity;magazynDokumentSkanPrzebiegOdswiez(documentId);return quantity;
}
function magazynDokumentSkanZmienIlosc(documentId,delta){const session=magazynDokumentSkanSesja(documentId);return magazynDokumentSkanUstawIlosc(documentId,(Number(session.pending?.quantity)||1)+Number(delta||0));}
function magazynDokumentAnulujBiezacaPozycje(documentId){
  const session=magazynDokumentSkanSesja(documentId);session.pending=null;if(session.nextLocation){session.proposedLocation=session.nextLocation;session.nextLocation="";}magazynDokumentSkanPrzebiegOdswiez(documentId);magazynDokumentSkanStatus("Odrzucono niezatwierdzony odczyt. Stan dokumentu nie został zmieniony.");
}
async function magazynDokumentZatwierdzBiezacaPozycje(documentId,{automatic=false}={}){
  const session=magazynDokumentSkanSesja(documentId),pending=session.pending,doc=magazynDokumentPoId(documentId);if(!pending||!doc||doc.status!=="draft")return !pending;if(session.busy)return false;if(!session.confirmedLocation){toast("Najpierw zeskanuj i zatwierdź półkę");return false;}
  session.busy=true;magazynDokumentSkanPrzebiegOdswiez(documentId);const identity=pending.productId?{productId:pending.productId}:{scanCode:pending.code};
  const d=await magazynDokumentOperacja("warehouse-document-line-upsert",{documentId,expectedRevision:doc.revision,...identity,location:session.confirmedLocation,quantity:Math.max(1,Number(pending.quantity)||1),mode:"increment",requestId:magazynDokumentRequestId("scan-confirm")},"");
  session.busy=false;if(!d){magazynDokumentSkanPrzebiegOdswiez(documentId);magazynDokumentSkanStatus(`Nie zapisano ${pending.name||pending.code}. Popraw dane i spróbuj ponownie.`);return false;}
  const location=d.line?.location||session.confirmedLocation;session.last={name:d.line?.name||pending.name||pending.code,added:pending.quantity,total:d.line?.quantity||pending.quantity,location};session.pending=null;magazynDokumentKamera.quantity=1;
  if(session.nextLocation){session.proposedLocation=session.nextLocation;session.nextLocation="";}
  magazynDokumentSkanPrzebiegOdswiez(documentId);magazynDokumentKameraOdswiezPodsumowanie(d.document||magazynDokumentPoId(documentId),session.last);
  magazynDokumentSkanStatus(`✅ ${automatic?"Poprzednia pozycja zatwierdzona automatycznie":"Pozycja zatwierdzona"}: ${session.last.added} szt. ${session.last.name} • ${magazynDokumentWidocznaLokalizacja(location)}`);if(!automatic)toast(`✅ Zatwierdzono ${session.last.added} szt. — ${session.last.name}`);return true;
}
async function magazynDokumentZatwierdzPozycjeIZmienLokalizacje(documentId){const session=magazynDokumentSkanSesja(documentId),next=session.nextLocation;if(!next)return;const saved=await magazynDokumentZatwierdzBiezacaPozycje(documentId);if(saved){session.proposedLocation=next;session.nextLocation="";magazynDokumentSkanPrzebiegOdswiez(documentId);magazynDokumentSkanStatus(`Pozycja zapisana. Teraz potwierdź nowe miejsce ${magazynDokumentWidocznaLokalizacja(next)}.`);}}
function magazynDokumentSkanForm(form,event,id){event?.preventDefault();const input=form.querySelector("[name=scanCode]"),code=String(input?.value||"").trim();if(!code){toast("Zeskanuj lub wpisz kod");input?.focus();return false;}void magazynDokumentDodajKod(id,code,1,false);if(input){input.value="";input.focus();}return false;}
async function magazynDokumentDodajKod(documentId,code,quantity=1,fromCamera=false){
  const parsed=typeof magazynQRParsujOdczyt==="function"?magazynQRParsujOdczyt(code):{type:"code",scanCode:String(code||"").trim()};
  if(parsed.type==="location"){magazynDokumentUstawLokalizacjeSkanu(documentId,parsed.code,{fromCamera});return true;}
  const session=magazynDokumentSkanSesja(documentId);if(session.busy){magazynDokumentSkanStatus("Trwa zatwierdzanie poprzedniej pozycji — poczekaj chwilę.");return false;}
  if(!session.confirmedLocation||session.proposedLocation){magazynDokumentSkanStatus("Najpierw zeskanuj lub wybierz półkę i naciśnij „Potwierdź półkę”.");toast("Najpierw potwierdź półkę");return false;}
  if(session.pending){const saved=await magazynDokumentZatwierdzBiezacaPozycje(documentId,{automatic:true});if(!saved)return false;quantity=1;}
  const product=magazynDokumentProduktPoOdczycie(parsed),raw=String(parsed.scanCode||parsed.raw||code||"").trim();session.pending={productId:product?.id||(parsed.type==="product"?parsed.productId:""),code:raw,name:product?.nazwa||`Kod ${raw}`,image:product?.zdjecie||"",ean:product?.gtin||product?.ean||raw,externalId:product?.externalId||product?.sku||"",quantity:Math.max(1,Number(quantity)||1),fromCamera};magazynDokumentKamera.quantity=session.pending.quantity;
  magazynDokumentSkanPrzebiegOdswiez(documentId);magazynDokumentSkanStatus(`Rozpoznano ${session.pending.name}. Ustaw ilość i zatwierdź albo zeskanuj następny produkt.`);return true;
}
