function magazynDokumentKameraStop(){const quantity=Math.max(1,Number(magazynDokumentKamera.quantity)||1);magazynDokumentKamera.active=false;if(magazynDokumentKamera.timer)clearTimeout(magazynDokumentKamera.timer);try{magazynDokumentKamera.zxingControls?.stop?.();}catch(error){}magazynDokumentKamera.stream?.getTracks?.().forEach(track=>track.stop());document.getElementById("warehouseCameraScanner")?.remove();magazynDokumentKamera={stream:null,detector:null,timer:null,active:false,busy:false,lastCode:"",lastAt:0,lastSeenAt:0,documentId:"",quantity,fallback:false,canvas:null,context:null,minimized:false,torch:false,zxingReader:null,zxingControls:null};}

function magazynDokumentLinieHTML(doc){
  return `<div id="warehouseDocumentLines" class="warehouse-document-lines"><div class="warehouse-worktable-wrap"><table class="log-table"><thead><tr><th>Produkt</th><th>Stan teraz</th><th>Ilość ${doc.type}</th><th>Lokalizacja</th><th>Po operacji</th><th></th></tr></thead><tbody>${(doc.lines||[]).map(line=>{const stock=stanMagazynuId(line.productId),after=doc.type==="PZ"?(stock===null?0:stock)+Number(line.quantity||0):stock===null?null:stock-Number(line.quantity||0),problem=doc.type==="WZ"&&(stock===null||after<0);return `<tr class="${problem?"warehouse-document-line-error":""}"><td><div class="warehouse-document-product">${line.image?`<img src="${esc(line.image)}" alt="">`:`<span>📦</span>`}<div><b>${esc(line.name)}</b><small>${esc(line.externalId||line.sku||line.producerCode||`ID ${line.productId}`)} • EAN ${esc(line.ean||"—")}</small><small>${line.scanCount?`skany: ${esc(line.scanCount)} • `:""}${esc(line.matchedBy||"")}</small></div></div></td><td><b>${stock===null?"niemonitorowany":`${esc(stock)} szt.`}</b></td><td>${doc.status==="draft"?`<div class="warehouse-document-qty"><button type="button" onclick="magazynDokumentUstawPozycje(${jsArg(doc.id)},${jsArg(line.productId)},${Math.max(1,Number(line.quantity)-1)},${jsArg(line.location||"")})">−</button><input aria-label="Ilość" value="${esc(line.quantity)}" inputmode="numeric" onchange="magazynDokumentUstawPozycje(${jsArg(doc.id)},${jsArg(line.productId)},this.value,${jsArg(line.location||"")})"><button type="button" onclick="magazynDokumentUstawPozycje(${jsArg(doc.id)},${jsArg(line.productId)},${Number(line.quantity)+1},${jsArg(line.location||"")})">＋</button></div>`:`<b>${esc(line.quantity)} szt.</b>`}</td><td>${doc.status==="draft"?`<input class="warehouse-document-location" value="${esc(line.location||"")}" placeholder="np. R1-P2" onchange="magazynDokumentUstawPozycje(${jsArg(doc.id)},${jsArg(line.productId)},${Number(line.quantity)},this.value)">`:`${esc(line.location||"—")}`}</td><td><b class="${problem?"text-danger":""}">${after===null?"wymaga stanu":`${esc(after)} szt.`}</b>${stock===null&&doc.type==="PZ"?`<small>rozpocznie kontrolę od 0</small>`:""}</td><td>${doc.status==="draft"?`<button class="btn danger" type="button" onclick="magazynDokumentUsunPozycje(${jsArg(doc.id)},${jsArg(line.lineId)})">Usuń</button>`:""}</td></tr>`;}).join("")||`<tr><td colspan="6">Dokument jest pusty. Zeskanuj kod albo wyszukaj produkt ręcznie.</td></tr>`}</tbody></table></div></div>`;
}
function magazynDokumentDecyzjaHTML(doc){
  if(magazynDokumentPotwierdzenieId===String(doc.id)){const qty=(doc.lines||[]).reduce((s,x)=>s+Number(x.quantity||0),0);return `<form class="warehouse-document-confirm" data-warehouse-document-decision="confirm" onsubmit="event.preventDefault();void magazynDokumentZatwierdz(${jsArg(doc.id)});return false"><div><b>${doc.type==="PZ"?"📥 Potwierdź przyjęcie":"📤 Potwierdź rozchód"}</b><p>Dokument <strong>${esc(doc.number)}</strong> zmieni stan ${(doc.lines||[]).length} produktów o łącznie ${qty} szt. Operacja zostanie zapisana w historii i nie będzie edytowalna.</p></div><label><input type="checkbox" required> Dane i ilości są zgodne ze stanem faktycznym</label><div class="diag-actions"><button class="btn ghost" type="button" onclick="magazynDokumentZamknijDecyzje()">Wróć</button><button class="btn" type="submit" ${magazynDokumentyStan.busy?"disabled":""}>${magazynDokumentyStan.busy?"Księguję…":`Potwierdzam ${esc(doc.type)}`}</button></div></form>`;}
  if(magazynDokumentAnulowanieId===String(doc.id))return `<form class="warehouse-document-confirm cancel" data-warehouse-document-decision="cancel" onsubmit="return magazynDokumentAnuluj(this,event,${jsArg(doc.id)})"><div><b>⛔ Anulowanie szkicu</b><p>Stan magazynu nie zostanie zmieniony, a dokument pozostanie w historii audytowej.</p></div><input name="reason" required minlength="3" maxlength="300" placeholder="Powód anulowania"><div class="diag-actions"><button class="btn ghost" type="button" onclick="magazynDokumentZamknijDecyzje()">Wróć</button><button class="btn danger" type="submit">Anuluj dokument</button></div></form>`;
  if(magazynDokumentUsuwanieId===String(doc.id))return `<form class="warehouse-document-confirm delete" data-warehouse-document-decision="delete" onsubmit="return magazynDokumentUsun(this,event,${jsArg(doc.id)})"><div><b>🗑️ Usuń szkic ${esc(doc.number)}</b><p>Szkic zniknie z listy i nie zmieni stanu magazynu. Podaj powód — numer, operator oraz czas pozostaną w audycie.</p></div><input name="reason" required minlength="3" maxlength="300" placeholder="Powód usunięcia szkicu"><div class="diag-actions"><button class="btn ghost" type="button" onclick="magazynDokumentZamknijDecyzje()">Wróć</button><button class="btn danger" type="submit" ${magazynDokumentyStan.busy?"disabled":""}>${magazynDokumentyStan.busy?"Usuwam…":"Usuń szkic"}</button></div></form>`;
  return "";
}
function magazynDokumentEditorHTML(doc){
  if(!doc)return `<div class="warehouse-document-empty"><span>🧾</span><b>Utwórz pierwszy dokument PZ albo WZ</b><p>PZ przyjmie istniejące gry na stan. WZ bezpiecznie zdejmie towar, nie pozwalając zejść poniżej zera.</p></div>`;
  const meta=magazynDokumentStatusMeta(doc.status),qty=(doc.lines||[]).reduce((s,x)=>s+Number(x.quantity||0),0);
  const isPz=doc.type==="PZ",operation=isPz?"PRZYJĘCIE NA STAN":"WYDANIE ZE STANU",quantityLabel=doc.status==="confirmed"?(isPz?"przyjęto":"wydano"):(isPz?"do przyjęcia":"do wydania");
  const draftWorkspace=doc.status==="draft"?`<section class="warehouse-document-workbench"><div class="warehouse-document-workbench-head"><div><small>KONTROLOWANY PRZEBIEG ${esc(doc.type)}</small><b>${isPz?"Przyjmij produkty szybko i bez pomyłek":"Wydaj produkty ze sprawdzeniem dostępnego stanu"}</b><span>Półka → produkt → ilość → zapis pozycji. Stan zmieni się dopiero po zatwierdzeniu całego dokumentu.</span></div><button class="btn" type="button" onclick="magazynDokumentKameraStart(${jsArg(doc.id)})">📷 Uruchom aparat</button></div><div class="warehouse-document-entry"><div class="warehouse-scan-context" data-warehouse-scan-context="${esc(doc.id)}">${magazynDokumentSkanKontekstWnetrzeHTML(doc.id)}</div><section><div><b>🔎 Czytnik USB/Bluetooth lub kod ręczny</b><small>Skanuj kolejno: półka → produkt → ustaw ilość → zatwierdź. Następny produkt może automatycznie zatwierdzić poprzedni.</small></div><form onsubmit="return magazynDokumentSkanForm(this,event,${jsArg(doc.id)})"><input name="scanCode" data-warehouse-scan-input="${esc(doc.id)}" inputmode="text" autocomplete="off" placeholder="QR półki, QR produktu, EAN, GTIN, SKU…"><button class="btn" type="submit">Rozpoznaj kod</button><button class="btn ghost" type="button" onclick="magazynDokumentKameraStart(${jsArg(doc.id)})">📷 Aparat</button></form></section><section><div><b>＋ Wybór produktu ręcznie</b><small>Użyj, jeśli etykieta jest uszkodzona albo produkt nie ma kodu do zeskanowania.</small></div><input placeholder="Nazwa, EAN, EXTERNAL_ID, SKU lub kod producenta…" value="${esc(magazynDokumentProduktSzukaj)}" oninput="magazynDokumentSzukajProdukt(this,${jsArg(doc.id)})"><div id="warehouseDocumentProductResults" class="warehouse-document-product-results">${magazynDokumentWynikiProduktowHTML(doc.id)}</div></section></div></section><details class="warehouse-document-meta-details"><summary><span>🧾 Dane dokumentu, źródło i uwagi</span><small>${esc(doc.reference||doc.warehouse||"uzupełnij dane dokumentu")}</small></summary><form class="warehouse-document-meta" onsubmit="return magazynDokumentZapiszMeta(this,event,${jsArg(doc.id)})"><label>Magazyn<input name="warehouse" value="${esc(doc.warehouse||"")}" required></label><label>Dokument źródłowy / kontrahent<input name="reference" value="${esc(doc.reference||"")}" placeholder="np. spis własny, dostawa nr…"></label><label>Uwagi<input name="note" value="${esc(doc.note||"")}" placeholder="Opcjonalna notatka"></label><button class="btn ghost" type="submit">Zapisz dane</button></form></details>`:"";
  const actions=doc.status==="draft"?`<button class="btn ghost" type="button" onclick="magazynDokumentPokazAnulowanie(${jsArg(doc.id)})">⛔ Anuluj i archiwizuj</button><button class="btn danger" type="button" onclick="magazynDokumentPokazUsuwanie(${jsArg(doc.id)})">🗑️ Usuń szkic</button>`:doc.status==="confirmed"?`<button class="btn ghost" type="button" onclick="magazynDokumentUtworzKorekte(${jsArg(doc.id)})">↩ Utwórz korektę ${isPz?"WZ":"PZ"}</button>`:"";
  const mobileActions=doc.status==="draft"?`<nav class="warehouse-document-mobile-actions" aria-label="Szybka obsługa dokumentu"><button type="button" onclick="magazynDokumentZamknij()"><span>←</span><small>Dokumenty</small></button><button type="button" onclick="magazynDokumentKameraStart(${jsArg(doc.id)})"><span>📷</span><small>Skanuj</small></button><button type="button" onclick="magazynDokumentPrzewinDo('#warehouseDocumentLines')"><span>📦</span><small>Pozycje</small></button><button class="primary" type="button" onclick="magazynDokumentPokazPotwierdzenie(${jsArg(doc.id)})" ${(doc.lines||[]).length?"":"disabled"}><span>✓</span><small>Zaksięguj</small></button></nav>`:`<nav class="warehouse-document-mobile-actions" aria-label="Nawigacja dokumentu"><button type="button" onclick="magazynDokumentZamknij()"><span>←</span><small>Dokumenty</small></button><button type="button" onclick="magazynDokumentPrzewinDo('#warehouseDocumentLines')"><span>📦</span><small>Pozycje</small></button><button type="button" onclick="magazynDokumentEksportuj(${jsArg(doc.id)})"><span>⇩</span><small>CSV</small></button></nav>`;
  return `<article class="warehouse-document-editor type-${esc(doc.type.toLowerCase())} status-${esc(doc.status)}"><header><div><span class="warehouse-document-type">${isPz?"📥":"📤"} ${esc(doc.type)}</span><div><small>${esc(meta.icon)} ${esc(meta.label)} • rewizja ${esc(doc.revision)}</small><h3 id="warehouseDocumentDialogTitle">${esc(doc.number)}</h3><p>${esc(doc.warehouse||"Magazyn główny")} • ${(doc.lines||[]).length} pozycji • ${qty} szt.${doc.correctionOfNumber?` • korekta ${esc(doc.correctionOfNumber)}`:""}</p></div></div><div class="diag-actions"><button class="btn ghost" type="button" onclick="magazynDokumentEksportuj(${jsArg(doc.id)})">📤 CSV</button>${actions}</div></header><div class="warehouse-document-operation-banner ${isPz?"is-pz":"is-wz"}"><div><span>${isPz?"📥":"📤"}</span><div><small>${doc.status==="draft"?"AKTYWNA OPERACJA":"DOKUMENT HISTORYCZNY"}</small><b>${esc(operation)}</b><em>${esc(doc.type)} • ${esc(doc.number)}</em></div></div><div class="warehouse-document-operation-metrics"><span><b>${(doc.lines||[]).length}</b><small>pozycji</small></span><span><b>${qty}</b><small>szt. ${esc(quantityLabel)}</small></span></div></div>${magazynDokumentDecyzjaHTML(doc)}${draftWorkspace}${magazynDokumentLinieHTML(doc)}<footer><div><b>${isPz?"PZ — przyjęcie zewnętrzne":"WZ — wydanie zewnętrzne"}</b><small>${doc.status==="draft"?"Skanowanie i edycja nie zmieniają stanów. Zmiana nastąpi dopiero po zatwierdzeniu całego dokumentu.":doc.status==="confirmed"?`Zaksięgowano ${esc(allegroDataTxt(doc.confirmedAt))} przez ${esc(doc.confirmedBy||"administrator")}`:`Anulowano ${esc(allegroDataTxt(doc.cancelledAt))}. Stan nie został zmieniony.`}</small></div>${doc.status==="draft"?`<button class="btn" type="button" onclick="magazynDokumentPokazPotwierdzenie(${jsArg(doc.id)})" ${(doc.lines||[]).length?"":"disabled"}>${isPz?"📥 Zatwierdź PZ":"📤 Zatwierdź WZ"}</button>`:""}</footer>${mobileActions}</article>`;
}
function magazynDokumentPasuje(doc){const q=magazynDokumentSzukaj.trim().toLowerCase(),type=magazynDokumentFiltrTyp==="wszystkie"||doc.type===magazynDokumentFiltrTyp,status=magazynDokumentFiltrStatus==="wszystkie"||magazynDokumentFiltrStatus==="aktywne"&&doc.status==="draft"||doc.status===magazynDokumentFiltrStatus;if(!type||!status)return false;return !q||`${doc.number} ${doc.warehouse} ${doc.reference} ${doc.note} ${(doc.lines||[]).map(x=>`${x.name} ${x.ean} ${x.externalId} ${x.sku}`).join(" ")}`.toLowerCase().includes(q);}
function magazynDokumentListaHTML(){const docs=(magazynDokumentyStan.items||[]).filter(magazynDokumentPasuje);return `<div class="warehouse-document-list">${docs.map(doc=>{const meta=magazynDokumentStatusMeta(doc.status),qty=(doc.lines||[]).reduce((s,x)=>s+Number(x.quantity||0),0),selected=String(magazynDokumentyStan.selectedId)===String(doc.id);return `<button type="button" class="${selected?"active":""} type-${esc(doc.type.toLowerCase())}" onclick="magazynDokumentWybierz(${jsArg(doc.id)})"><span>${doc.type==="PZ"?"📥":"📤"}</span><div><b>${esc(doc.number)}</b><small>${esc(meta.label)} • ${(doc.lines||[]).length} pozycji • ${qty} szt.</small><small>${esc(doc.reference||doc.warehouse||"")}</small></div><em>${esc(allegroDataTxt(doc.updatedAt))}</em></button>`;}).join("")||`<div class="warehouse-document-empty small"><b>Brak dokumentów dla wybranych filtrów</b></div>`}</div>`;}
function magazynDokumentyPanelWnetrzeHTML(){
  if(magazynDokumentyStan.loading&&!magazynDokumentyStan.loaded)return `<div class="warehouse-document-loading">⏳ Pobieram dokumenty magazynowe…</div>`;
  const all=magazynDokumentyStan.items||[],drafts=all.filter(x=>x.status==="draft"),confirmed=all.filter(x=>x.status==="confirmed"),pz=all.filter(x=>x.type==="PZ"&&x.status==="confirmed"),wz=all.filter(x=>x.type==="WZ"&&x.status==="confirmed"),selected=magazynDokumentWybrany();
  const error=magazynDokumentyStan.error?`<div class="backend-note warn"><b>Dokumenty magazynowe:</b> ${esc(magazynDokumentyStan.error)} <button class="btn ghost" onclick="magazynDokumentyLaduj(true)">Ponów</button></div>`:"";
  if(selected)return `${error}<div id="warehouseDocumentWorkspace" class="warehouse-document-focus"><nav class="warehouse-document-focus-nav"><button class="btn ghost" type="button" onclick="magazynDokumentZamknij()">← Wszystkie dokumenty</button><div><span>${selected.type==="PZ"?"📥 Przyjęcie zewnętrzne":"📤 Wydanie zewnętrzne"}</span><b>${esc(selected.number)}</b><small>${selected.status==="draft"?"Szkic roboczy — stan jeszcze się nie zmienił":magazynDokumentStatusMeta(selected.status).label}</small></div><button class="btn ghost" type="button" onclick="magazynDokumentyLaduj(true)">↻ Odśwież</button></nav>${magazynDokumentEditorHTML(selected)}</div>`;
  return `${error}<div class="warehouse-document-head"><div><span class="order-pro-label">Niezależne operacje magazynowe</span><h2>📑 Dokumenty przyjęcia i rozchodu</h2><p>Każdy dokument otwiera osobny pełny obszar roboczy. PZ przyjmuje towar, WZ kontroluje rozchód, a stan zmienia dopiero końcowe księgowanie.</p></div><details class="warehouse-document-create" ${all.length?"":"open"}><summary>＋ Nowy dokument</summary><form onsubmit="return magazynDokumentUtworz(this,event)"><label>Typ<select name="type"><option value="PZ">PZ — przyjęcie zewnętrzne</option><option value="WZ">WZ — wydanie zewnętrzne</option></select></label><label>Magazyn<input name="warehouse" value="${esc(ustawieniaMagazynuPelne().nazwa||"Magazyn główny")}" required></label><label>Źródło / kontrahent<input name="reference" placeholder="np. towar własny, dokument dostawy"></label><label>Uwagi<input name="note" placeholder="Opcjonalnie"></label><button class="btn" type="submit" ${magazynDokumentyStan.busy?"disabled":""}>Utwórz i otwórz szkic</button></form></details></div><div class="warehouse-document-stats"><button onclick="magazynDokumentFiltrStatus='aktywne';magazynDokumentFiltrTyp='wszystkie';magazynDokumentyOdswiezPanel()"><span>✏️</span><b>${drafts.length}</b><small>szkice</small></button><button onclick="magazynDokumentFiltrStatus='confirmed';magazynDokumentFiltrTyp='PZ';magazynDokumentyOdswiezPanel()"><span>📥</span><b>${pz.length}</b><small>przyjęcia PZ</small></button><button onclick="magazynDokumentFiltrStatus='confirmed';magazynDokumentFiltrTyp='WZ';magazynDokumentyOdswiezPanel()"><span>📤</span><b>${wz.length}</b><small>rozchody WZ</small></button><button onclick="magazynDokumentFiltrStatus='confirmed';magazynDokumentFiltrTyp='wszystkie';magazynDokumentyOdswiezPanel()"><span>✅</span><b>${confirmed.length}</b><small>zaksięgowane</small></button></div><div class="warehouse-document-layout warehouse-document-browser"><aside><div class="warehouse-document-filters"><input placeholder="Szukaj dokumentu lub produktu…" value="${esc(magazynDokumentSzukaj)}" oninput="magazynDokumentFiltrujSzukaj(this)"><select onchange="magazynDokumentFiltrTyp=this.value;magazynDokumentyOdswiezPanel()"><option value="wszystkie" ${magazynDokumentFiltrTyp==="wszystkie"?"selected":""}>PZ i WZ</option><option value="PZ" ${magazynDokumentFiltrTyp==="PZ"?"selected":""}>Tylko PZ</option><option value="WZ" ${magazynDokumentFiltrTyp==="WZ"?"selected":""}>Tylko WZ</option></select><select onchange="magazynDokumentFiltrStatus=this.value;magazynDokumentyOdswiezPanel()"><option value="aktywne" ${magazynDokumentFiltrStatus==="aktywne"?"selected":""}>Szkice aktywne</option><option value="confirmed" ${magazynDokumentFiltrStatus==="confirmed"?"selected":""}>Zaksięgowane</option><option value="cancelled" ${magazynDokumentFiltrStatus==="cancelled"?"selected":""}>Anulowane</option><option value="wszystkie" ${magazynDokumentFiltrStatus==="wszystkie"?"selected":""}>Wszystkie</option></select></div>${magazynDokumentListaHTML()}</aside></div>`;
}
function magazynDokumentyPanelHTML(){if(!magazynDokumentyStan.loaded&&!magazynDokumentyStan.loading)setTimeout(()=>magazynDokumentyLaduj(),0);return `<section id="warehouseDocumentsCenter" class="panel warehouse-documents-center">${magazynDokumentyPanelWnetrzeHTML()}</section>`;}
